import { Component, Prop, h, Element, Event, EventEmitter, Host } from '@stencil/core';

@Component({
  tag: 'wdpr-segmented-horizontal-tab',
  styleUrl: 'wdpr-segmented-horizontal-tab.css',
  scoped: true,
})
export class WdprSegmentedHorizontalTab {
  @Element() el: HTMLWdprSegmentedHorizontalTabElement;

  /**
   * Tab id
   * @type {string}
   */
  @Prop() tabId: string;

  /**
   * Tab label
   * @type {string}
   */
  @Prop() label: string;

  /**
   * Tab icon
   * @type {string}
   */
  @Prop() icon: string;

  /**
   * if `true`, the tab is currently active.
   * @type {boolean}
   */
  @Prop({ reflect: true, mutable: true }) active: boolean = false;

  /**
   * if `true`, the tab is disabled
   * @type {boolean}
   */
  @Prop({ reflect: true, mutable: true }) disabled: boolean = false;

  /**
   * The id of the element that this tab controls
   * @type {string}
   */
  @Prop() controlsId: string;

  /**
   * The tabindex of the tab
   * @type {number}
   */
  @Prop() customTabIndex: number;

  @Prop({ attribute: 'a11y-label'}) a11yLabel: string;

  /**
   * Emitted when the tab button is clicked.
   * This is used by the parent wdpr-tab-bar to manage the active state.
   */
  @Event() tabClicked: EventEmitter<{ tabElement: unknown }>;

  private _handleClick = () => {
    if (this.disabled) {
      return;
    }

    this.tabClicked.emit({ tabElement: this.el });
  };

  render() {
    return (
      <Host
        id={this.tabId}
        role="tab"
        tabindex={this.disabled ? -1 : (this.customTabIndex ?? 0)}
        aria-selected={this.active ? 'true' : 'false'}
        aria-controls={this.controlsId}
        aria-disabled={this.disabled ? 'true' : undefined}
        aria-label={this.a11yLabel}
        onClick={this._handleClick}
      >
        {this.icon && <wdpr-icon-library icon={this.icon} size="medium" decorative />}
        {this.label && <span class="segmented-horizontal-tab-main-label">{this.label}</span>}
      </Host>
    );
  }
}
